#include <stdio.h>
#include <stdlib.h>

// Define the structure for a stone
typedef struct Stone {
    int x;
    int y;
} Stone;

// Define the structure for a Union Find data structure
typedef struct UnionFind {
    int* parent;
    int size;
} UnionFind;

// Function to create a new Union Find data structure
UnionFind* createUnionFind(int size) {
    UnionFind* uf = (UnionFind*) malloc(sizeof(UnionFind));
    uf->parent = (int*) malloc(size * sizeof(int));
    uf->size = size;
    for (int i = 0; i < size; i++) {
        uf->parent[i] = i;
    }
    return uf;
}

// Function to find the parent of a node in the Union Find data structure
int find(UnionFind* uf, int x) {
    if (uf->parent[x] != x) {
        uf->parent[x] = find(uf, uf->parent[x]);
    }
    return uf->parent[x];
}

// Function to union two nodes in the Union Find data structure
void unionNodes(UnionFind* uf, int x, int y) {
    int rootX = find(uf, x);
    int rootY = find(uf, y);
    if (rootX != rootY) {
        uf->parent[rootX] = rootY;
    }
}

// Function to remove stones
int removeStones(Stone* stones, int stonesSize) {
    UnionFind* uf = createUnionFind(2 * stonesSize);
    for (int i = 0; i < stonesSize; i++) {
        unionNodes(uf, stones[i].x, stones[i].y + stonesSize);
    }
    int count = 0;
    for (int i = 0; i < stonesSize; i++) {
        if (find(uf, stones[i].x) == stones[i].x) {
            count++;
        }
    }
    return stonesSize - count;
}

int main() {
    Stone stones[] = {{0, 0}, {0, 1}, {1, 0}, {1, 2}, {2, 1}, {2, 2}};
    int stonesSize = sizeof(stones) / sizeof(stones[0]);
    printf("%d\n", removeStones(stones, stonesSize));
    return 0;
}

